#include <iostream>
#include <string>
#include <cmath>
#include <algorithm>

class Solution {
public:
    std::string largestPalindrome(int n, int k) {
        int max_digits = (std::log10(std::max(n, k)) + 1);
        std::string result;
        for (int i = max_digits; i >= 0; i--) {
            int num = pow(10, i) * k;
            if (num <= n && is_palindrome(num)) {
                result = std::to_string(num);
                break;
            }
        }
        return result;
    }

    bool is_palindrome(int num) {
        int num_abs = abs(num);
        int left = 0, right = num_abs - 1;
        while (left < right) {
            if (num_abs % 10 != num_abs / 10) {
                return false;
            }
            num_abs = num_abs / 10;
            left++;
            right--;
        }
        return true;
    }
};
```

